arguments.new_str:
// -- ApplyCoupon tests --

[TestMethod]
public void ApplyCoupon_Save10_Applies10Percent()
{
    var calc = new DiscountCalculator();
    Assert.AreEqual(90m, calc.ApplyCoupon(100m, "SAVE10"));
}

[TestMethod]
public void ApplyCoupon_Save20_Applies20Percent()
{
    var calc = new DiscountCalculator();
    Assert.AreEqual(80m, calc.ApplyCoupon(100m, "SAVE20"));
}

[TestMethod]
public void ApplyCoupon_Flat5_SubtractsFive()
{
    var calc = new DiscountCalculator();
    Assert.AreEqual(95m, calc.ApplyCoupon(100m, "FLAT5"));
}

[TestMethod]
public void ApplyCoupon_Flat50_SubtractsFifty()
{
    var calc = new DiscountCalculator();
    Assert.AreEqual(150m, calc.ApplyCoupon(200m, "FLAT50"));
}

[TestMethod]
public void ApplyCoupon_UnknownCoupon_ReturnsOriginalTotal()
{
    var calc = new DiscountCalculator();
    Assert.AreEqual(100m, calc.ApplyCoupon(100m, "BOGUS"));
}

[TestMethod]
public void ApplyCoupon_LowercaseCode_StillApplies()
{
    var calc = new DiscountCalculator();
    Assert.AreEqual(90m, calc.ApplyCoupon(100m, "save10"));
}

[TestMethod]
public void ApplyCoupon_FloorAt1_WhenDiscountExceedsTotal()
{
    var calc = new DiscountCalculator();
    // FLAT50 on a 10.00 order: 10 - 50 = -40 → clamped to 1.00
    Assert.AreEqual(1.00m, calc.ApplyCoupon(10m, "FLAT50"));
}

[TestMethod]
public void ApplyCoupon_ExactlyAtFloor_Returns1()
{
    var calc = new DiscountCalculator();
    // FLAT5 on 6.00: 6.00 - 5.00 = 1.00 — exactly at floor
    Assert.AreEqual(1.00m, calc.ApplyCoupon(6.00m, "FLAT5"));
}

[TestMethod]
public void ApplyCoupon_JustAboveFloor_ReturnsActualResult()
{
